function Map_select () {
    if (Map == 1) {
        tiles.setCurrentTilemap(tilemap`level4`)
    } else if (Map == 2) {
        tiles.setCurrentTilemap(tilemap`level3`)
    } else if (Map == 3) {
        tiles.setCurrentTilemap(tilemap`level2`)
    } else if (Map == 4) {
        tiles.setCurrentTilemap(tilemap`level5`)
    } else if (Map == 5) {
        game.gameOver(true)
    } else if (Map == 6) {
    	
    } else if (Map == 7) {
    	
    } else if (Map == 8) {
    	
    } else if (Map == 9) {
    	
    } else if (Map == 10) {
    	
    } else if (Map == 11) {
    	
    }
    tiles.placeOnRandomTile(mySprite2, sprites.dungeon.floorLight0)
    tiles.placeOnRandomTile(mySprite, sprites.dungeon.floorLight0)
}
info.onCountdownEnd(function () {
    Key_anim = 1
    mySprite3 = sprites.create(assets.image`Key`, SpriteKind.Food)
    tiles.placeOnRandomTile(mySprite3, sprites.dungeon.floorLight0)
})
